import { useState, useEffect } from 'react';

export default function ScheduleSection() {
  const [schedule, setSchedule] = useState([]);

  useEffect(() => {
    generateWeekSchedule();
  }, []);

  function generateWeekSchedule() {
    const days = ['Domingo', 'Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado'];
    const today = new Date();
    const startOfWeek = new Date(today);
    startOfWeek.setDate(today.getDate() - today.getDay()); // Domingo como início da semana

    const weekDays = [];
    for (let i = 0; i < 6; i++) { // Segunda a Sábado
      const day = new Date(startOfWeek);
      day.setDate(startOfWeek.getDate() + 1 + i); // Começando na segunda (índice 1)

      if (day.getDay() !== 0 && day.getDay() !== 6) { // Apenas dias úteis (Seg-Sex)
        // Actually, let's include Saturday as per requirements (seg-sab)
        const dayName = days[day.getDay()];
        const formattedDate = day.toLocaleDateString('pt-BR', { day: 'numeric', month: 'short' });

        const hours = [];
        for (let h = 8; h <= 18; h++) {
          const timeString = `${h.toString().padStart(2, '0')}:00`;
          hours.push({
            time: timeString,
            displayTime: `${h}h`,
            date: day,
            dayName,
            formattedDate
          });
        }

        weekDays.push({
          dayName,
          formattedDate,
          date: day,
          hours
        });
      }
    }

    setSchedule(weekDays);
  }

  function getWhatsAppLink(date, time) {
    // Replace with actual WhatsApp number
    const phoneNumber = "5511999999999"; // Example Brazilian number
    const message = encodeURIComponent(`Olá, gostaria de agendar uma consulta para o dia ${date.toLocaleDateString('pt-BR')} às ${time}.`);
    return `https://wa.me/${phoneNumber}?text=${message}`;
  }

  if (schedule.length === 0) {
    return <div className="py-20 text-center">Carregando horários...</div>;
  }

  return (
    <section id="agendar" className="py-20 bg-white">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <h2 className="text-3xl font-bold text-center mb-16 text-gray-800">
          Agende uma Consulta
        </h2>
        <div className="space-y-8">
          {schedule.map((day, dayIndex) => (
            <div key={dayIndex}>
              <h3 className="text-2xl font-semibold text-gray-800 mb-4">
                {day.dayName}, {day.formattedDate}
              </h3>
              <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
                {day.hours.map((hour, hourIndex) => (
                  <a
                    key={hourIndex}
                    href={getWhatsAppLink(day.date, hour.time)}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="block bg-blue-50 hover:bg-blue-100 text-blue-800 font-medium py-3 px-4 rounded-lg text-center transition-colors border border-blue-200 hover:border-blue-300"
                  >
                    {hour.displayTime}
                  </a>
                ))}
              </div>
            </div>
          ))}
        </div>
        <p className="mt-8 text-center text-gray-600 text-sm">
          Os links abrem uma conversa pré-formatada no WhatsApp para agendamento.
          <br />
          Horários disponíveis: Segunda a Sábado, das 8h às 18h.
        </p>
      </div>
    </section>
  );
}